import { ChatOpenAI } from "langchain/chat_models/openai";
import { BufferWindowMemory } from "langchain/memory";

const tiktoken = require('tiktoken'); // npm install tiktoken

function monitorContextOverflow(memory: BufferWindowMemory, model: ChatOpenAI, maxTokens: number = 8000) {
  const encoder = tiktoken.getEncoding('cl100k_base');

  const originalLoad = memory.loadMemoryVariables;

  memory.loadMemoryVariables = async function(variables: any) {
    const result = await originalLoad.call(this, variables);

    const history = result.history || [];
    let totalTokens = 0;

    for (const msg of history) {
      totalTokens += encoder.encode(msg.content).length;
    }

    if (totalTokens > maxTokens * 0.8) {
      console.warn(`🚨 Context overflow risk: ${totalTokens}/${maxTokens} tokens`);
      // Auto-trim oldest messages
      while (totalTokens > maxTokens * 0.7 && history.length > 5) {
        history.shift();
        totalTokens -= encoder.encode(history[0]?.content || '').length;
      }
    }

    return result;
  };

  return memory;
}
