from langchain.agents import AgentExecutor
from typing import Dict, Any
from collections import defaultdict

class LoopProofAgentExecutor(AgentExecutor):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.tool_usage = defaultdict(int)
        self.max_tool_calls = 3

    def _take_next_step(self, **kwargs) -> Dict[str, Any]:
        action = kwargs['agent_outcome']
        tool_name = action.tool

        # Enforce tool cooldown
        if self.tool_usage[tool_name] >= self.max_tool_calls:
            return {
                'output': f'Tool {tool_name} usage limit exceeded. Switching to fallback reasoning.'
            }

        self.tool_usage[tool_name] += 1
        return super()._take_next_step(**kwargs)
