from langchain.retrievers import ContextualCompressionRetriever
from langchain.retrievers.document_compressors import EmbeddingsFilter

class AdaptiveRAG:
    def __init__(self, primary_retriever, fallback_retriever, threshold=0.7):
        self.primary = primary_retriever
        self.fallback = fallback_retriever
        self.threshold = threshold

    def retrieve(self, query):
        docs = self.primary.get_relevant_documents(query)

        # Quick relevance check
        if len(docs) == 0 or self._avg_relevance(query, docs) < self.threshold:
            print('🔄 Low confidence retrieval, falling back to web search')
            return self.fallback.get_relevant_documents(query)

        return docs

    def _avg_relevance(self, query, docs):
        # Simplified relevance scoring
        query_words = set(query.lower().split())
        doc_scores = []
        for doc in docs[:3]:
            doc_words = set(doc.page_content.lower().split())
            overlap = len(query_words.intersection(doc_words))
            doc_scores.append(overlap / len(query_words))
        return sum(doc_scores) / len(doc_scores)
