from langchain.output_parsers import PydanticOutputParser
from pydantic import BaseModel, Field
from langchain.prompts import PromptTemplate

class ToolCall(BaseModel):
    name: str = Field(description="Tool name")
    args: dict = Field(description="Tool arguments as JSON")

class StructuredAgent:
    def __init__(self, llm):
        self.parser = PydanticOutputParser(pydantic_object=ToolCall)
        self.llm = llm

        prompt = PromptTemplate(
            template="Answer in JSON format: {format_instructions}\nQuery: {query}",
            input_variables=["query"],
            partial_variables={"format_instructions": self.parser.get_format_instructions()}
        )

        self.chain = prompt | llm | self.parser

    def invoke(self, query):
        try:
            return self.chain.invoke({"query": query})
        except Exception:
            return ToolCall(name="fallback_reasoning", args={})
